sql:
SELECT AVG(calorie_burned) AS average_calories_burned
FROM daily_activity
WHERE user_id = 1 AND date BETWEEN '2023-03-01' AND '2023-03-31';

SELECT COUNT(progress_id) AS total_progress_entries
FROM progress_tracking
WHERE user_id = 0 AND progress_metric = 'body fat percentage' AND progress_value > goal_value;

SELECT AVG(steps) AS average_steps
FROM daily_activity
WHERE date = '2023-03-01';

SELECT AVG(steps) AS average_steps
FROM daily_activity
WHERE date = '2023-03-02';

SELECT date
FROM daily_activity
ORDER BY date DESC;

SELECT AVG(steps) AS average_steps
FROM daily_activity
WHERE steps >= steps_goal;

external_knowledge:
- "quite active" refers to users with more than 2000 calories burned; 
- "moving more than 5000 steps on average" means their daily average steps are over 5000;
- "recent workout session longer than 45 minutes" refers to workouts conducted between March 15 and March 31, 2023, with a duration exceeding 45 minutes.

sql:
SELECT COUNT(DISTINCT user_id) AS total_active_users
FROM fitness_plans
WHERE status = 'active';

SELECT date, minutes_of_sleep
FROM sleep_data
ORDER BY minutes_of_sleep DESC;

SELECT COUNT(DISTINCT da.user_id) AS total_users_with_activity_and_sleep
FROM daily_activity da
JOIN sleep_data sd ON da.user_id = sd.user_id;
